from pathlib import Path
import base64
import gzip


def decode(value: str) -> str:
    return gzip.decompress(base64.b64decode(value)).decode('utf-8')


prefix = decode('')
css_append = decode('')

page_path = Path('src/pages/StaticPages.tsx')
current = page_path.read_text(encoding='utf-8')
marker = 'export function Contact({ lang }: Props) {'
index = current.find(marker)
if index < 0:
    raise SystemExit('Contact marker not found in StaticPages.tsx')
page_path.write_text(prefix + current[index:], encoding='utf-8')

css_path = Path('src/styles/pages/static.css')
css_current = css_path.read_text(encoding='utf-8')
css_marker = '/* Static pages content v2: long-form About, Terms and Privacy. */'
if css_marker not in css_current:
    css_path.write_text(css_current.rstrip() + css_append, encoding='utf-8')

updated = page_path.read_text(encoding='utf-8')
checks = {
    'about content': 'Nền tảng giao dịch tư nhân cho doanh nghiệp Việt toàn cầu' in updated,
    'about line icons': '<GoalIcon />' in updated and '<GlobeIcon />' in updated,
    'about other icons removed': 'const pillars =' not in updated and 'const flows =' not in updated,
    'terms warning removed': 'function Notice' not in updated and '<Notice' not in updated,
    'privacy CTA removed': 'Questions about privacy?' not in updated,
    'terms sections': len(__import__('re').findall(r'viTitle:', Path('src/content/staticTermsContent1.ts').read_text() + Path('src/content/staticTermsContent2.ts').read_text())) == 28,
    'privacy sections': len(__import__('re').findall(r'viTitle:', Path('src/content/staticPrivacyContent1.ts').read_text() + Path('src/content/staticPrivacyContent2.ts').read_text())) == 20,
}
failed = [name for name, ok in checks.items() if not ok]
if failed:
    raise SystemExit('Static page assertions failed: ' + ', '.join(failed))
